sql.if:
AND (
    p.owner_user_id = #{viewer_user_id}
    OR EXISTS (
        SELECT 1
        FROM schedule_project_member pm
        WHERE pm.project_id = p.project_id
          AND pm.user_id = #{viewer_user_id}
    )
)

mapper.select:
WITH filtered_project AS ( SELECT p.project_id, p.project_status FROM schedule_project p
AND p.project_type_code = #{project_type_code}
), filtered_task AS ( SELECT t.task_status, t.due_date FROM schedule_task t INNER JOIN filtered_project p ON p.project_id = t.project_id ), filtered_milestone AS ( SELECT m.due_date FROM schedule_milestone m INNER JOIN filtered_project p ON p.project_id = m.project_id ), project_summary AS ( SELECT COUNT(*) AS project_total, COUNT(*) FILTER (WHERE project_status = 'PLANNING') AS project_planning, COUNT(*) FILTER (WHERE project_status = 'IN_PROGRESS') AS project_in_progress, COUNT(*) FILTER (WHERE project_status = 'DONE') AS project_done FROM filtered_project ), task_summary AS ( SELECT COUNT(*) AS task_total, COUNT(*) FILTER (WHERE task_status = 'TODO') AS task_todo, COUNT(*) FILTER (WHERE task_status = 'IN_PROGRESS') AS task_in_progress, COUNT(*) FILTER (WHERE task_status = 'DONE') AS task_done, COUNT(*) FILTER (WHERE due_date < CURRENT_DATE AND task_status <> 'DONE') AS overdue_task_count FROM filtered_task ), milestone_summary AS ( SELECT COUNT(*) FILTER (WHERE due_date BETWEEN CURRENT_DATE AND CURRENT_DATE + 30) AS upcoming_milestone_count FROM filtered_milestone ) SELECT ps.project_total, ps.project_planning, ps.project_in_progress, ps.project_done, ts.task_total, ts.task_todo, ts.task_in_progress, ts.task_done, ts.overdue_task_count, ms.upcoming_milestone_count FROM project_summary ps CROSS JOIN task_summary ts CROSS JOIN milestone_summary ms

SELECT p.project_id, p.project_key, p.project_name, p.project_type_code, p.project_status, p.owner_user_id, p.start_date AS project_start_date, p.end_date AS project_end_date, COUNT(t.task_id) AS task_count, COUNT(t.task_id) FILTER (WHERE t.task_status = 'DONE') AS done_count, COUNT(t.task_id) FILTER (WHERE t.due_date < CURRENT_DATE AND t.task_status <> 'DONE') AS overdue_count, COALESCE(ROUND(AVG(t.progress_rate)::numeric, 1), 0) AS progress_avg, COALESCE(SUM(t.support_amount), 0) AS support_total, COALESCE(SUM(t.actual_amount), 0) AS actual_total, MIN(t.start_date) AS target_start_date, MAX(t.due_date) AS target_end_date, MIN(t.actual_start_date) AS actual_start_date, MAX(t.actual_end_date) AS actual_end_date, CASE WHEN p.project_type_code = 'BLOG' THEN '업체 부담금' WHEN p.project_type_code = 'DEVELOPMENT' THEN '진행률' ELSE '진행률' END AS main_metric_label, CASE WHEN p.project_type_code = 'BLOG' THEN COALESCE(SUM(t.support_amount), 0) ELSE COALESCE(ROUND(AVG(t.progress_rate)::numeric, 1), 0) END AS main_metric_value, CASE WHEN p.project_type_code = 'BLOG' THEN '추가 결제금' WHEN p.project_type_code = 'DEVELOPMENT' THEN '완료' ELSE '완료' END AS sub_metric_label, CASE WHEN p.project_type_code = 'BLOG' THEN COALESCE(SUM(t.actual_amount), 0) ELSE COUNT(t.task_id) FILTER (WHERE t.task_status = 'DONE') END AS sub_metric_value FROM schedule_project p LEFT JOIN schedule_task t ON t.project_id = p.project_id
AND p.project_type_code = #{project_type_code}
GROUP BY p.project_id, p.project_key, p.project_name, p.project_type_code, p.project_status, p.owner_user_id, p.start_date, p.end_date ORDER BY p.project_type_code, p.project_id DESC

WITH typed_task AS ( SELECT p.project_type_code, CASE WHEN p.project_type_code = 'DEVELOPMENT' THEN COALESCE(t.actual_end_date, t.due_date, t.start_date) ELSE COALESCE(t.due_date, t.start_date) END AS basis_date, t.task_status, t.due_date, t.progress_rate, t.support_amount, t.actual_amount FROM schedule_task t INNER JOIN schedule_project p ON p.project_id = t.project_id
AND p.project_type_code = #{project_type_code}
) SELECT TO_CHAR(DATE_TRUNC('month', basis_date), 'YYYY-MM') AS month_key, project_type_code, COUNT(*) AS task_count, COUNT(*) FILTER (WHERE task_status = 'DONE') AS done_count, COUNT(*) FILTER (WHERE due_date < CURRENT_DATE AND task_status <> 'DONE') AS overdue_count, COALESCE(ROUND(AVG(progress_rate)::numeric, 1), 0) AS progress_avg, COALESCE(SUM(support_amount), 0) AS support_total, COALESCE(SUM(actual_amount), 0) AS actual_total FROM typed_task WHERE basis_date IS NOT NULL GROUP BY DATE_TRUNC('month', basis_date), project_type_code ORDER BY month_key DESC, project_type_code LIMIT 36
